import { useSuspenseQueries } from '@tanstack/react-query';
import { Suspense } from 'react';
import { useIntl, FormattedMessage } from 'react-intl';

import { SkeletonText } from '../../../content/skeleton/SkeletonText.js';
import { Flex } from '../../../layouts/flex/Flex.js';
import { Text } from '../../../typography/text/Text.js';
import {
  segmentsClient,
  useSegmentsCache,
  type CachedSegment,
} from '../contexts/SegmentsCache/SegmentsCache.js';
import { useSegments } from '../hooks/useSegments.js';
import { SEGMENTSELECTOR_MESSAGES } from '../segmentMessages.js';
import * as styles from '../SegmentSelector.sty.js';
import { getReadableValue } from '../utils.js';

/** @internal */
const SegmentWithVariablesText = ({
  id,
  name,
  variables,
}: {
  id: string;
  name?: string;
  variables?: string[];
}) => {
  const intl = useIntl();
  const endOfLine = variables && variables.length > 1 ? ';' : '';
  const values =
    variables?.map((value) => getReadableValue(value, intl)).join(', ') +
    endOfLine;

  return (
    <div key={id} style={{ lineHeight: 1 }}>
      <Text textStyle="small-emphasized">{name}: </Text>
      <Text textStyle="small">{values}</Text>
    </div>
  );
};

/** @internal */
const WrappedTooltipMessages = ({ ariaLabel }: { ariaLabel?: string }) => {
  const { segments } = useSegments();
  const { getSegment } = useSegmentsCache();
  const result = useSuspenseQueries(
    {
      queries: segments.map((segment) => ({
        queryKey: ['getSegment', segment.id],
        queryFn: () => getSegment(segment.id),
        select: (data: CachedSegment | undefined) => ({
          selectedSegment: segment,
          fetchedSegment: data?.segment,
        }),
        retryOnMount: false,
      })),
    },
    segmentsClient.queryClient,
  );

  if (segments.length === 0) {
    return (
      <Text textStyle="small-emphasized" className={styles.tooltipMaxHeight}>
        {ariaLabel ?? (
          <FormattedMessage {...SEGMENTSELECTOR_MESSAGES.defaultAriaLabel} />
        )}
      </Text>
    );
  }

  return (
    <Flex flexDirection="column" gap={4} className={styles.tooltipMaxHeight}>
      {result.map((query) => {
        const selectedSegment = query.data?.selectedSegment;
        const id = selectedSegment.id;
        const name = query.data?.fetchedSegment?.name ?? id;

        if (selectedSegment?.variables) {
          return (
            <SegmentWithVariablesText
              key={id}
              id={id}
              name={name}
              variables={selectedSegment.variables?.[0]?.values}
            />
          );
        }

        return (
          <Text key={id} textStyle="small-emphasized">
            {name}
          </Text>
        );
      })}
    </Flex>
  );
};

export const TooltipMessages = ({ ariaLabel }: { ariaLabel?: string }) => (
  /** Due to display: 'contents' on the tooltip we need to define a fixed width here. */
  <Suspense fallback={<SkeletonText width="150px" />}>
    <WrappedTooltipMessages ariaLabel={ariaLabel} />
  </Suspense>
);
